class FreqStack:
    def __init__(self):
        self.items = []

    def push(self, val):
        self.items.append(val)

    def pop(self):
        counts = {}
        for v in self.items:
            counts[v] = counts.get(v, 0) + 1
        best = max(counts.values())
        for i in range(len(self.items) - 1, -1, -1):
            if counts[self.items[i]] == best:
                return self.items.pop(i)

